import sys

data = list(map(int, sys.stdin.read().split()))
m, n = data[0], data[1]
values = data[2:]
dp = [[0] * n for _ in range(m)]
index = 0

for row in range(m):
    for col in range(n):
        value = values[index]
        index += 1
        if row == 0 and col == 0:
            dp[row][col] = value
        elif row == 0:
            dp[row][col] = dp[row][col - 1] + value
        elif col == 0:
            dp[row][col] = dp[row - 1][col] + value
        else:
            dp[row][col] = min(dp[row - 1][col], dp[row][col - 1]) + value

print(dp[m - 1][n - 1])
